11	/**
12	 * @brief Proxy class for a sub-matrix of a NdMatrix class.
13	 * 
14	 * This is used to allow chaining of array indexing [] operators in a natural way.
15	 *
16	 * Each instance of this class peels off one-dimension and returns a NdMatrixProxy representing
17	 * the resulting sub-matrix. This is repeated recursively until we hit the 1-dimensional base-case.
18	 *
19	 * Since this expansion happens at compiler time all the proxy classes get optimized away,
20	 * yielding both high performance and generality.
21	 * 
22	 * Recursive case: N-dimensional array
23	 */
24	template<typename T, size_t N>
25	class NdMatrixProxy {
26	  public:
27	    static_assert(N > 0, "Must have at least one dimension");
28	
29	    /**
30	     * @brief Construct a matrix proxy object
31	     *
32	     *    @param dim_sizes: Array of dimension sizes
33	     *    @param dim_stride: The stride of this dimension (i.e. how many element in memory between indices of this dimension)
34	     *    @param offset: The offset from the start that this sub-matrix starts at.
35	     *    @param start: Pointer to the start of the base NDMatrix of this proxy
36	     */
37	    NdMatrixProxy(const size_t* dim_sizes, const size_t* dim_strides, size_t offset, const std::unique_ptr<T[]>& start)
38	        : dim_sizes_(dim_sizes)
39	        , dim_strides_(dim_strides)
40	        , offset_(offset)
41	        , start_(start) {}
42	
43	    NdMatrixProxy(const NdMatrixProxy&) = default;
44	    NdMatrixProxy& operator=(const NdMatrixProxy& other) = delete;
45	
46	    ///@brief const [] operator
47	    const NdMatrixProxy<T, N - 1> operator[](size_t index) const {
48	        VTR_ASSERT_SAFE_MSG(index < dim_sizes_[0], "Index out of range (above dimension maximum)");
49	        VTR_ASSERT_SAFE_MSG(dim_sizes_[1] > 0, "Can not index into zero-sized dimension");
50	
51	        // Strip off one dimension
52	        return NdMatrixProxy<T, N - 1>(
53	            dim_sizes_ + 1,                    // Pass the dimension information
54	            dim_strides_ + 1,                  // Pass the stride for the next dimension
55	            offset_ + dim_strides_[0] * index, // Advance to index in this dimension
56	            start_);                           // Pass the base pointer.
57	    }
58	
59	    ///@brief [] operator
60	    NdMatrixProxy<T, N - 1> operator[](size_t index) {
61	        // Call the const version and cast-away constness
62	        return const_cast<const NdMatrixProxy<T, N>*>(this)->operator[](index);
63	    }
64	
65	  private:
66	    /// @brief The sizes of each dimension of this proxy. This is an array of
67	    ///        length N.
68	    const size_t* dim_sizes_;
69	
70	    /// @brief The stride of each dimension of this proxy. This is an array of
71	    ///        length N.
72	    const size_t* dim_strides_;
73	
74	    /// @brief The offset from the base NDMatrix object that this sub-matrix
75	    ///        starts at.
76	    size_t offset_;
77	
78	    /// @brief The pointer to the start of the base NDMatrix data. Since the
79	    ///        base NDMatrix object owns the memory, we hold onto a reference
80	    ///        to its unique pointer. This is safer than passing a bare pointer.
81	    const std::unique_ptr<T[]>& start_;
82	};
83	
84	///@brief Base case: 1-dimensional array
85	template<typename T>
86	class NdMatrixProxy<T, 1> {
87	  public:
88	    /**
89	     * @brief Construct a 1-d matrix proxy object
90	     *
91	     *    @param dim_sizes: Array of dimension sizes
92	     *    @param dim_stride: The stride of this dimension (i.e. how many element in memory between indices of this dimension)
93	     *    @param offset: The offset from the start that this sub-matrix starts at.
94	     *    @param start: Pointer to the start of the base NDMatrix of this proxy
95	     */
96	    NdMatrixProxy(const size_t* dim_sizes, const size_t* dim_stride, size_t offset, const std::unique_ptr<T[]>& start)
97	        : dim_sizes_(dim_sizes)
98	        , dim_strides_(dim_stride)
99	        , offset_(offset)
100	        , start_(start) {}
101	
102	    NdMatrixProxy(const NdMatrixProxy&) = default;
103	    NdMatrixProxy& operator=(const NdMatrixProxy& other) = delete;
104	
105	    ///@brief const [] operator
106	    const T& operator[](size_t index) const {
107	        VTR_ASSERT_SAFE_MSG(dim_strides_[0] == 1, "Final dimension must have stride 1");
108	        VTR_ASSERT_SAFE_MSG(index < dim_sizes_[0], "Index out of range (above dimension maximum)");
109	
110	        //Base case
111	        return start_[offset_ + index];
112	    }
113	
114	    ///@brief [] operator
115	    T& operator[](size_t index) {
116	        // Call the const version and cast-away constness
117	        return const_cast<T&>(const_cast<const NdMatrixProxy<T, 1>*>(this)->operator[](index));
118	    }
119	
120	    /**
121	     * @brief  Backward compitibility
122	     *
123	     * For legacy compatibility (i.e. code expecting a pointer) we allow this base dimension
124	     * case to retrieve a raw pointer to the last dimension elements.
125	     *
126	     * Note that it is the caller's responsibility to use this correctly; care must be taken
127	     * not to clobber elements in other dimensions
128	     */
129	    const T* data() const {
130	        return start_.get() + offset_;
131	    }
132	
133	    ///@brief same as above but allow update the value
134	    T* data() {
135	        // Call the const version and cast-away constness
136	        return const_cast<T*>(const_cast<const NdMatrixProxy<T, 1>*>(this)->data());
137	    }
138	
139	  private:
140	    /// @brief The sizes of each dimension of this proxy. This is an array of
141	    ///        length N.
142	    const size_t* dim_sizes_;
143	
144	    /// @brief The stride of each dimension of this proxy. This is an array of
145	    ///        length N.
146	    const size_t* dim_strides_;
147	
148	    /// @brief The offset from the base NDMatrix object that this sub-matrix
149	    ///        starts at.
150	    size_t offset_;
151	
152	    /// @brief The pointer to the start of the base NDMatrix data. Since the
153	    ///        base NDMatrix object owns the memory, we hold onto a reference
154	    ///        to its unique pointer. This is safer than passing a bare pointer.
155	    const std::unique_ptr<T[]>& start_;
156	};
