158	/**
159	 * @brief Base class for an N-dimensional matrix
160	 *
161	 * Base class for an N-dimensional matrix supporting arbitrary index ranges per dimension.
162	 * This class implements all of the matrix handling (lifetime etc.) except for indexing
163	 * (which is implemented in the NdMatrix class). Indexing is split out to allows specialization
164	 * (of indexing for N = 1.
165	 *
166	 * Implementation:
167	 * 
168	 * This class uses a single linear array to store the matrix in c-style (row major)
169	 * order. That is, the right-most index is laid out contiguous memory.
170	 *
171	 * This should improve memory usage (no extra pointers to store for each dimension),
172	 * and cache locality (less indirection via pointers, predictable strides).
173	 *
174	 * The indices are calculated based on the dimensions to access the appropriate elements.
175	 * Since the indexing calculations are visible to the compiler at compile time they can be
176	 * optimized to be efficient.
177	 */
178	template<typename T, size_t N>
179	class NdMatrixBase {
180	  public:
181	    static_assert(N >= 1, "Minimum dimension 1");
182	
183	    ///@brief An empty matrix (all dimensions size zero)
184	    NdMatrixBase() {
185	        clear();
186	    }
187	
188	    /**
189	     * @brief Specified dimension sizes:
190	     *
191	     *      [0..dim_sizes[0])
192	     *      [0..dim_sizes[1])
193	     *      ...
194	     *      with optional fill value
195	     */
196	    NdMatrixBase(std::array<size_t, N> dim_sizes, T value = T()) {
197	        resize(dim_sizes, value);
198	    }
199	
200	  public: //Accessors
201	    ///@brief Returns the size of the matrix (number of elements)
202	    size_t size() const {
203	        VTR_ASSERT_DEBUG_MSG(calc_size() == size_, "Calculated and current matrix size must be consistent");
204	        return size_;
205	    }
206	
207	    ///@brief Returns true if there are no elements in the matrix
208	    bool empty() const {
209	        return size() == 0;
210	    }
211	
212	    ///@brief Returns the number of dimensions (i.e. N)
213	    size_t ndims() const {
214	        return dim_sizes_.size();
215	    }
216	
217	    ///@brief Returns the size of the ith dimension
218	    size_t dim_size(size_t i) const {
219	        VTR_ASSERT_SAFE(i < ndims());
220	
221	        return dim_sizes_[i];
222	    }
223	
224	    ///@brief Returns the starting index of ith dimension
225	    size_t begin_index(size_t i) const {
226	        VTR_ASSERT_SAFE(i < ndims());
227	
228	        return 0;
229	    }
230	
231	    ///@brief Returns the one-past-the-end index of the ith dimension
232	    size_t end_index(size_t i) const {
233	        VTR_ASSERT_SAFE(i < ndims());
234	
235	        return dim_sizes_[i];
236	    }
237	
238	    ///@brief const Flat accessors of NdMatrix
239	    const T& get(size_t i) const {
240	        VTR_ASSERT_SAFE(i < size_);
241	        return data_[i];
242	    }
243	
244	    ///@brief Flat accessors of NdMatrix
245	    T& get(size_t i) {
246	        VTR_ASSERT_SAFE(i < size_);
247	        return data_[i];
248	    }
249	
250	  public: //Mutators
251	    ///@brief Set all elements to 'value'
252	    void fill(T value) {
253	        if (size() > 0) {
254	            std::fill(data_.get(), data_.get() + size(), value);
255	        }
256	    }
257	
258	    /**
259	     * @brief Resize the matrix to the specified dimension ranges
260	     *
261	     * If 'value' is specified all elements will be initialized to it,
262	     * otherwise they will be default constructed.
263	     */
264	    void resize(std::array<size_t, N> dim_sizes, T value = T()) {
265	        dim_sizes_ = dim_sizes;
266	        size_ = calc_size();
