279	    ///@brief Reset the matrix to size zero
280	    void clear() {
281	        data_.reset(nullptr);
282	        dim_sizes_.fill(0);
283	        dim_strides_.fill(0);
284	        size_ = 0;
285	    }
286	
287	  public: //Lifetime management
288	    ///@brief Copy constructor
289	    NdMatrixBase(const NdMatrixBase& other)
290	        : NdMatrixBase(other.dim_sizes_) {
291	        std::copy(other.data_.get(), other.data_.get() + other.size(), data_.get());
292	    }
