310	    ///@brief Swap two NdMatrixBase objects
311	    friend void swap(NdMatrixBase<T, N>& m1, NdMatrixBase<T, N>& m2) {
312	        using std::swap;
313	        swap(m1.size_, m2.size_);
314	        swap(m1.dim_sizes_, m2.dim_sizes_);
315	        swap(m1.dim_strides_, m2.dim_strides_);
316	        swap(m1.data_, m2.data_);
317	    }
