357	 *       NdMatrix<int,3> m2({5,10,20});
358	 * 
359	 *       //A 2-dimensional matrix with indices [0..4][0..9], with all entries
360	 *       //initialized to 42
361	 *       NdMatrix<int,2> m3({5,10}, 42);
