394	            this->dim_sizes_.data() + 1,   //Pass the dimension information
395	            this->dim_strides_.data() + 1, //Pass the stride for the next dimension
396	            this->dim_strides_[0] * index, //Advance to index in this dimension
397	            this->data_);                  //Pass the base pointer
398	    }
399	
400	    /**
401	     * @brief Access an element
402	     *
403	     * Returns a proxy-object to allow chained array-style indexing
404	     */
405	    NdMatrixProxy<T, N - 1> operator[](size_t index) {
406	        //Call the const version, since returned by value don't need to worry about const
407	        return const_cast<const NdMatrix<T, N>*>(this)->operator[](index);
408	    }
409	};
