426	        VTR_ASSERT_SAFE_MSG(index >= 0, "Index out of range (below dimension minimum)");
427	        VTR_ASSERT_SAFE_MSG(index < this->dim_sizes_[0], "Index out of range (above dimension maximum)");
428	
