2	
3	#include <cstddef>
4	#include <utility>
5	#include <vector>
6	
7	#include "vtr_assert.h"
8	#include "vtr_sentinels.h"
9	
10	namespace vtr {
11	
12	/**
13	 * @brief A vector-like container which is indexed by K (instead of size_t as in std::vector).
14	 * 
15	 * The main use of this container is to behave like a std::vector which is indexed by
16	 * vtr::StrongId.
17	 * 
18	 * Requires that K be convertible to size_t with the size_t operator (i.e. size_t()), and
19	 * that the conversion results in a linearly increasing index into the underlying vector.
20	 * 
21	 * This results in a container that is somewhat similar to a std::map (i.e. converts from one
22	 * type to another), but requires contiguously ascending (i.e. linear) keys. Unlike std::map
23	 * only the values are stored (at the specified index/key), reducing memory usage and improving
24	 * cache locality. Furthermore, operator[] and find() return the value or iterator directly
25	 * associated with the value (like std::vector) rather than a std::pair (like std::map).
26	 * insert() takes both the key and value as separate arguments and has no return value.
27	 * 
28	 * Additionally, vector_map will silently create values for 'gaps' in the index range (i.e.
29	 * those elements are initialized with Sentinel::INVALID()).
30	 * 
31	 * If you need a fully featured std::map like container without the above differences see
32	 * vtr::linear_map.
33	 * 
34	 * If you do not need std::map-like features see vtr::vector. Note that vtr::vector_map is very similar 
35	 * to vtr::vector. Unless there is a specific reason that vtr::vector_map is needed, it is better to use vtr::vector.
36	 * 
37	 * Note that it is possible to use vector_map with sparse/non-contiguous keys, but this is typically
38	 * memory inefficient as the underlying vector will allocate space for [0..size_t(max_key)-1],
39	 * where max_key is the largest key that has been inserted.
40	 * 
41	 * As with a std::vector, it is the caller's responsibility to ensure there is sufficient space
42	 * when a given index/key before it is accessed. The exception to this are the find(), insert() and
43	 * update() methods which handle non-existing keys gracefully.
44	 */
45	
